"use strict";(globalThis.webpackChunkggv_blogs=globalThis.webpackChunkggv_blogs||[]).push([[648],{3807(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>h,default:()=>d,frontMatter:()=>o,gallery1Images:()=>g,gallery2Images:()=>u,metadata:()=>n,toc:()=>c});const n=JSON.parse('{"id":"GijsGroteVleesverbouwing/bbq","title":"Barbecue","description":"In Gijs Great Meat Makeover, Gijs mainly uses his barbecue to make great food.","source":"@site/i18n/en/docusaurus-plugin-content-docs/current/3_GijsGroteVleesverbouwing/1_bbq.mdx","sourceDirName":"3_GijsGroteVleesverbouwing","slug":"/GijsGroteVleesverbouwing/bbq","permalink":"/en/GijsGroteVleesverbouwing/bbq","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2},"sidebar":"GijsGroteVleesverbouwing","previous":{"title":"Intro","permalink":"/en/GijsGroteVleesverbouwing/"},"next":{"title":"Pulled pork","permalink":"/en/GijsGroteVleesverbouwing/pulledPork"}}');var i=a(4848),r=a(8453),s=a(5643);const o={sidebar_position:2},h="Barbecue",l={},g=[{original:"/img/ggvv/bbq/IMG_20201003_121733-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201003_121733-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201003_121743-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201003_121743-scaled.jpg"}],u=[{original:"/img/ggvv/bbq/IMG_20201105_142326-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142326-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_142337-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142337-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_142710-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142710-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_142345-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142345-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_144706-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_144706-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_144825_1-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_144825_1-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_144814-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_144814-scaled.jpg"}],c=[{value:"Snake Method",id:"snake-method",level:2},{value:"Minion Method",id:"minion-method",level:2}];function b(e){const t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"barbecue",children:"Barbecue"})}),"\n","\n","\n",(0,i.jsx)(t.p,{children:"In Gijs Great Meat Makeover, Gijs mainly uses his barbecue to make great food.\nA good barbecue is nice to have, but not everyone wants to spend 600 to 1200 euros on one, and honestly, you do not have to.\nSure, an expensive barbecue can make things easier, so if you grill a lot and have the budget, Gijs definitely recommends it.\nBut in Gijs Great Meat Makeover, he wants to show that you can also make amazing dishes on a simple barbecue.\nThe most important thing is that your barbecue has a lid."}),"\n",(0,i.jsx)(t.h1,{id:"charcoal-or-briquettes",children:"Charcoal or Briquettes?"}),"\n",(0,i.jsx)(t.p,{children:"Gijs believes a real barbecue runs on charcoal or briquettes. Gas and electric barbecues are not really his thing.\nWhen using a charcoal barbecue, the classic question always comes up: \u201cDo I use charcoal or briquettes?\u201d"}),"\n",(0,i.jsx)(t.p,{children:"Both fuels come from the same source. Charcoal is partially burned wood that burns more steadily than regular wood.\nBy limiting oxygen during the burn process, only the more volatile and less predictable elements are burned off.\nWhat remains are dry carbon pieces that burn very steadily. Briquettes are basically ground and compressed charcoal: same material, just much denser.\nBoth have pros and cons. Charcoal burns a bit hotter than briquettes, but it burns out faster.\nBriquettes burn a little cooler, but more consistently."}),"\n",(0,i.jsx)(t.p,{children:"Everyone has their own preference, and Gijs is not going to pretend one is always better than the other.\nHe personally prefers briquettes for low-and-slow barbecue because they burn longer.\nThe temperature difference is minimal in this method, because the lid stays on.\nFor direct grilling, he more often uses charcoal because it gets going a bit faster."}),"\n",(0,i.jsx)("img",{src:"/img/ggvv/bbq/IMG_20201025_095244-scaled.jpg",alt:"coal",loading:"lazy",width:"100%"}),"\n",(0,i.jsx)(t.h1,{id:"lighting-the-barbecue",children:"Lighting the Barbecue"}),"\n",(0,i.jsx)(t.p,{children:"Gijs has a fairly large barbecue that can sometimes be harder to control, so using a good lighting method is extra important for him.\nSimply filling a chimney starter with briquettes, lighting it, and dumping it in the barbecue gives you a very high starting temperature that then drops quickly.\nThat can burn the outside of the meat while leaving the inside undercooked."}),"\n",(0,i.jsx)(t.h2,{id:"snake-method",children:"Snake Method"}),"\n",(0,i.jsxs)(t.p,{children:["To keep his barbecue under control for a long time, Gijs uses the ",(0,i.jsx)("a",{href:"https://bbqware.be/tips-en-technieken/minion-snake-houtskool-techniek.php",children:"snake method"})," for arranging briquettes."]}),"\n",(0,i.jsx)(t.p,{children:"By creating a long, snake-like stack of briquettes and only lighting the ends, the fire slowly follows the trail.\nThis keeps the barbecue from getting too hot and means Gijs barely has to add briquettes.\nIf you have a smaller barbecue, it is usually smarter to light the snake on just one side, otherwise temperatures can rise too high."}),"\n",(0,i.jsxs)(t.p,{children:["By making the snake wider with extra layers, Gijs can run the barbecue hotter.\nThat does not mean you should throw away your chimney starter, though.\nIt is very useful for lighting a small batch of coals that you place at the start of the snake (see ",(0,i.jsx)("a",{href:"https://youtu.be/Dw3hn8aXPxc",children:"this"})," video).\nWith the snake method, it can take 1 to 2 hours before enough coals are burning to hit your target temperature, and a few hot starter coals can reduce that startup time a lot."]}),"\n",(0,i.jsx)(s.A,{items:g,loading:"lazy"}),"\n",(0,i.jsx)(t.h2,{id:"minion-method",children:"Minion Method"}),"\n",(0,i.jsxs)(t.p,{children:["The ",(0,i.jsx)("a",{href:"https://www.youtube.com/watch?v=c7cURxn-I7w",children:"minion method"})," is another common way to keep a barbecue hot for longer.\nThis method usually lasts a bit less long than the snake method above, but it is useful for reaching higher temperatures, for example when baking bread."]}),"\n",(0,i.jsx)(t.p,{children:"Building the minion setup is very similar to the snake setup, except the snake is now a full ring with no start or end.\nYou also do not have to be as neat with the minion method as with the snake method.\nAfter that, Gijs lights some coals in a chimney starter, and when they are burning, he pours them into the center of the ring.\nThose hot center coals then gradually light the coals around them."}),"\n",(0,i.jsx)(t.p,{children:"Compared to the snake method, more coals burn at the same time here, so the barbecue runs hotter.\nThe trade-off is that fuel burns out faster, so refilling is needed sooner."}),"\n",(0,i.jsx)(s.A,{items:u,loading:"lazy"}),"\n",(0,i.jsx)(t.h1,{id:"wood-or-coconut",children:"Wood or Coconut"}),"\n",(0,i.jsxs)(t.p,{children:["There are a lot of ",(0,i.jsx)("a",{href:"https://braadmaarraak.nl/kokosbriketten-overzicht/#:~:text=Ook%20bereiken%20kokosbriketten%20eenvoudig%20een,dan%20met%20n%C3%B3g%20meer%20voordelen",children:"positive stories"})," about using coconut briquettes instead of charcoal.\nAt the time of writing, Gijs has not used them yet, but he is open to trying them.\nAs soon as he has more experience with coconut briquettes, you will find a full review here."]})]})}function d(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(b,{...e})}):b(e)}}}]);